# GraphQL Schema
type_defs = """
    type Query {
        me: User
        user(id: ID!): User
        users: [User!]!
        post(id: ID!): Post
        posts(authorId: ID, publishedOnly: Boolean): [Post!]!
    }

    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        published: Boolean!
        author: User!
    }
"""

# Resolvers
query = QueryType()
user_type = ObjectType("User")
post_type = ObjectType("Post")


@query.field("me")
def resolve_me(_, info):
    current_user = info.context.get("current_user")
    if current_user is None:
        return None
    return USERS.get(current_user)


@query.field("user")
def resolve_user(_, info, id):
    return USERS.get(id)


@query.field("users")
def resolve_users(_, info):
    return list(USERS.values())


@query.field("post")
def resolve_post(_, info, id):
    return POSTS.get(id)


@query.field("posts")
def resolve_posts(_, info, authorId=None, publishedOnly=None):
    results = list(POSTS.values())
    if authorId is not None:
        results = [p for p in results if p.author_id == authorId]
    if publishedOnly:
        results = [p for p in results if p.published]
    return results


# User field resolvers
@user_type.field("posts")
def resolve_user_posts(user, info):
    return [POSTS[pid] for pid in user.post_ids if pid in POSTS]


@user_type.field("email")
def resolve_user_email(user, info):
    current_user = info.context.get("current_user")
    # For now, return the email - field-level permissions will be added later
    # Private field: only visible to the user themselves
    if current_user == user.id:
        return user.email
    return None


@user_type.field("phone")
def resolve_user_phone(user, info):
    current_user = info.context.get("current_user")
    if current_user == user.id:
        return user.phone
    return None


@user_type.field("address")
def resolve_user_address(user, info):
    current_user = info.context.get("current_user")
    if current_user == user.id:
        return user.address
    return None


# Post field resolvers
@post_type.field("author")
def resolve_post_author(post, info):
    return USERS.get(post.author_id)


# Create executable schema
schema = make_executable_schema(type_defs, query, user_type, post_type)


# Authentication middleware
class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts authentication info from request headers
    and sets current_user in the request state.

    Expects an 'Authorization' header with format: 'Bearer <user_id>'
    For simplicity, we use user IDs directly as tokens.
    """

    async def dispatch(self, request: Request, call_next):
        current_user = None
        auth_header = request.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            token = auth_header[7:].strip()
            # In a real app, you'd validate a JWT or session token here
            if token in USERS:
                current_user = token
        request.state.current_user = current_user
        response = await call_next(request)
        return response


def get_context_value(request: Request):
    """Build GraphQL context from the request, including auth info set by middleware."""
    current_user = getattr(request.state, "current_user", None)
    return {
        "request": request,
        "current_user": current_user,
    }


# Create ASGI app with middleware
app = GraphQL(
    schema,
    context_value=get_context_value,
    debug=True,
)

# Wrap with authentication middleware
from starlette.applications import Starlette
from starlette.routing import Route, Mount

starlette_app = Starlette(
    routes=[Mount("/", app=app)],
    middleware=[Middleware(AuthenticationMiddleware)],
)


